codeExamples.code:
# Two layers, each restricted to its region's working hours.
# PagerDuty fills overnight gaps in one layer from the other.
resource "pagerduty_schedule" "payments_24x7" {
  name      = "Payments 24x7"
  time_zone = "UTC"

  # Region A (e.g. Europe) covers 07:00-19:00 UTC
  layer {
    name                         = "EU daytime"
    start                        = "2024-01-01T07:00:00Z"
    rotation_virtual_start       = "2024-01-01T07:00:00Z"
    rotation_turn_length_seconds = 604800 # weekly
    users = [var.eu_user_1, var.eu_user_2, var.eu_user_3]

    restriction {
      type              = "daily_restriction"
      start_time_of_day = "07:00:00"
      duration_seconds  = 43200 # 12h
    }
  }

  # Region B (e.g. US) covers 19:00-07:00 UTC
  layer {
    name                         = "US daytime"
    start                        = "2024-01-01T19:00:00Z"
    rotation_virtual_start       = "2024-01-01T19:00:00Z"
    rotation_turn_length_seconds = 604800
    users = [var.us_user_1, var.us_user_2, var.us_user_3]

    restriction {
      type              = "daily_restriction"
      start_time_of_day = "19:00:00"
      duration_seconds  = 43200
    }
  }
}

# Engineer on the EU layer is out next week.
# Don't reshuffle the rotation, just override the window.
curl -s -X POST \
  "https://api.pagerduty.com/schedules/PSCHED01/overrides" \
  -H "Authorization: Token token=$PD_TOKEN" \
  -H "Content-Type: application/json" \
  -d '{
    "override": {
      "start": "2024-06-10T07:00:00Z",
      "end":   "2024-06-17T07:00:00Z",
      "user":  { "id": "PUSER02", "type": "user_reference" }
    }
  }'
